---@class LDisplaySpineCtrl
local LDisplaySpineCtrl = LxClass("LDisplaySpineCtrl",nil)

function LDisplaySpineCtrl:LDisplaySpineCtrl()
    self._objList = {}
end

--[[
    local data =
    {
        trans,
        key = "mainRole",
        localPos = pos,
        pos = pos,
        resName = spineName,
        scale = 0.7,
        endFunc = function (spine)
        end,
        enableClick = true,
        spineType ,
        sorting
    }
]]

function LDisplaySpineCtrl:MakeObject(objData)
    local key = objData.key
    local objectData = self._objList[key]
    local spine = nil
    if objectData then
        objectData.objData = objData
        if objectData.isLoaded then
            self:OnSpineLoaded(key)
        end
        spine = objectData.spine
    else
        spine = LDisplaySpine:New()
        objectData = {spine = spine,objData = objData}
        self._objList[key] = objectData
        local trans = objData.trans
        local spineName = objData.resName
        local spineType = objData.spineType or LDisplaySpine.TYPE_MODEL
        spine:CreateSpine(trans, spineName,spineType)
        spine:SetLoadedFunction(function()
            self:OnSpineLoaded(key)
        end)
        spine:StartLoad()
    end

    return spine
end

function LDisplaySpineCtrl:OnSpineLoaded(key)

    local objectData = self._objList[key]
    if not objectData then
        return
    end
    objectData.isLoaded = true
    local spine = objectData.spine
    local objData = objectData.objData

    local dpTrans = spine:GetDisplayTrans()
    if not CS.IsValidObject(dpTrans) then
        return
    end
    if objData.pos then
        dpTrans.position =objData.pos
    end

    local localPos = objData.localPos or Vector3.zero
    dpTrans.localPosition = localPos

    if objData.scale then
        spine:SetScale(objData.scale)
    end

    if objData.angle then
        local angle = objData.angle
        dpTrans.localRotation = Quaternion.Euler(angle.x,angle.y,angle.z)
    end

    local sorting = objData.sorting or 0
    local layer = objData.layer or "Object"
    spine:SetRenderOrder(sorting)
    spine:SetRenderLayer(layer)
    if objData.isLeft then
        spine:SetFlipX(objData.isLeft)
    end

    if objData.endFunc then
        objData.endFunc(spine)
    end
end

function LDisplaySpineCtrl:Clear()
    for k,v in pairs(self._objList) do
        local spine= v.spine
        spine:Destroy()
    end
    self._objList = {}
end

function LDisplaySpineCtrl:DestroyByKey(key)
    local spineData = self._objList[key]
    self._objList[key] = nil
    if spineData then
        local spine = spineData.spine
        spine:Destroy()
    end

end

function LDisplaySpineCtrl:FindObjByKey(key)
    local spineData = self._objList[key]
    if spineData then
        return spineData.spine
    end
end

function LDisplaySpineCtrl:RefreshAllRenderLayer(layer,order)
    for k,v in pairs(self._objList) do
        local spine= v.spine
        spine:SetRenderOrder(order)
        spine:SetRenderLayer(layer)
    end
end

return LDisplaySpineCtrl